    except Exception:
        return "Slide 6 (index 5) not found in pptx.", 0.0

    layout_name = slide_obj.slide_layout.name
    layout_name_normalized = layout_name.strip().lower().replace('-', ' ').replace('_', ' ')

    # Check for various possible "Two Content" layout names
    two_content_variants = [
        "two content",
        "two content layout", 
        "content with caption",
        "comparison", 
        "two objects",
        "side by side"
    ]

    # Also check if the slide actually has two content placeholders
    content_placeholders = []
    for shape in slide_obj.shapes:
        if shape.is_placeholder:
            placeholder = shape.placeholder_format
            # Check for content placeholders (types 1, 7, 13)
            if placeholder.type in [1, 7, 13]:  # CONTENT, OBJECT, CONTENT_WITH_CAPTION
                content_placeholders.append(placeholder.type)

    # Check layout name variants
    for variant in two_content_variants:
        if variant in layout_name_normalized:
            return f"Slide 6 has '{layout_name}' layout which matches 'Two Content'.", 1.0

    # Check if slide has exactly 2 content placeholders
    if len(content_placeholders) >= 2:
        return f"Slide 6 has {len(content_placeholders)} content placeholders, which indicates a 'Two Content' style layout (layout name: '{layout_name}').", 1.0

    # If neither condition is met, check the original slide layout detection
    if slide.layout_type:
        slide_layout_variants = slide.layout_type.strip().lower().replace('-', ' ').replace('_', ' ')
        for variant in two_content_variants:
