def compute_score() -> tuple[str, float]:
    import pptx
    prs = pptx.Presentation(modified_ppt_path)
    try:
        slide = prs.slides[5]  # Slide 6 (0-based)
    except Exception:
        return "Slide 6 not found.", 0.0
    # Get all placeholder shapes (only content placeholders)
    placeholders = [shape for shape in slide.shapes if shape.is_placeholder]
    # Filter placeholders for 'Content' type
    content_placeholders = []
    for ph in placeholders:
        # Looking for 'Content' or 'Two Content' types
        try:
            ph_type = ph.placeholder_format.idx
        except Exception:
            continue
        # Allowing all placeholders except title and objects (idx==0 or idx==7 are typically title/object)
        if ph_type > 0 and ph_type != 7:
            content_placeholders.append(ph)
        elif hasattr(ph, 'name') and 'content' in ph.name.lower():
            content_placeholders.append(ph)
    # Edge: .pptx layouts vary, but typically two content have at least two content placeholders.
    # Now check for 'Assets'/'Liabilities' in their text
    assets_found = False
    liabilities_found = False
    assets_box = None
    liabilities_box = None
    for ph in content_placeholders:
        text = ph.text.lower()
        if 'assets' in text:
            assets_found = True
            assets_box = ph
        if 'liabilities' in text:
            liabilities_found = True
            liabilities_box = ph
    # They must not be in the same placeholder (if both appear in one box, it's a fail)
    if not assets_found:
        return "No content placeholder contains 'Assets'.", 0.0
    if not liabilities_found:
        return "No content placeholder contains 'Liabilities'.", 0.0
    if assets_box is not None and liabilities_box is not None and assets_box != liabilities_box:
        return "'Assets' and 'Liabilities' are in separate content placeholders.", 1.0
    else:
        return "'Assets' and 'Liabilities' are in the same placeholder or not properly separated.", 0.0

