            break
    # If slide_id_6 not found, skip (can't evaluate)
    if not slide_id_6:
        return "Could not confidently check extraneous modifications on slide 6.", 1.0
    # Find if there are added/removed animations or transitions on slide 6
    for anim in ppt_diff.added_animations:
        if anim.slide_id == slide_id_6:
            unexpected_changes.append("Added animation")
    for anim in ppt_diff.removed_animations:
