            unexpected_changes.append("Removed animation")
    for anim1, anim2 in ppt_diff.modified_animations:
        if anim1.slide_id == slide_id_6 or anim2.slide_id == slide_id_6:
            unexpected_changes.append("Modified animation")
    for trans in ppt_diff.added_transitions:
